    private APIEntry handleAPIQueryFlag(APIQuery aq, RequestParam rp, boolean mobile, String formRulesPolicy, boolean isInfo,
      boolean isConversation, boolean isApproval, HttpServletRequest request) {
      if(mobile) {
        if (formRulesPolicy!=null) {
          if ("true".equalsIgnoreCase(formRulesPolicy)) {
            aq.setFormRulesPolicy(Const.API_FORMRULES_FULL);
          } else {
            aq.setFormRulesPolicy(Const.API_FORMRULES);
          }
        } else {
          aq.setFormRulesPolicy(Const.API_NO_FORMRULES);
        }

        if(isInfo) aq.setIfIncludeInfo(true);
        if(isConversation) aq.setIfConversations(true);
        if(isApproval) aq.setIfApproval(true);
      }

      boolean zapier= request.getParameter("zapier") != null;
      boolean integromat= request.getParameter("integromat") != null;
      boolean upd = request.getParameter("upd") != null;

      if((zapier || integromat) && upd) {
          int ni = Encoder.parseInt(request.getParameter("ni"), -1);
          APIEntry ae = aq.getAPIEntry(ni);

          if(ae == null) {
              String keyword = request.getParameter("keyword");
              int keyDomain = Encoder.parseInt(request.getParameter("keyDomain"), -1);

              aq.addFilter(keyDomain, "=", keyword);
              ae = aq.getAPIResult();
          }

          if(ae == null) {
            ae = aq.insertAPIEntry();
          }

          return ae;
      } else {
        if(rp.getNodeId()>=0){
          return aq.getAPIEntry(rp.getNodeId());
        } else {
          return aq.insertAPIEntry();
        }
      }
    }

private void setServiceExecuteTrigger(APIEntry ae, boolean ifApp, boolean ifEmbededWeb) {
    if(ifApp) {
        ae.setTrigger(new MobileTrigger());
    } else if(ifEmbededWeb) {
    	ae.setTrigger(new EmbededWebTrigger(EmbededWebTrigger.Type.DATABASE_FORM));
    } else {
    	ae.setTrigger(new HTTPAPITrigger());
    }
}

